package com.mengwei.localgrowth.strategy;

import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.mengwei.localgrowth.audit.AuditService;
import com.mengwei.localgrowth.identity.AuthService.Identity;
import com.mengwei.localgrowth.shared.ApiExceptionHandler.ApiException;
import java.net.URI;
import java.time.OffsetDateTime;
import java.util.*;
import org.springframework.http.HttpStatus;
import org.springframework.jdbc.core.namedparam.MapSqlParameterSource;
import org.springframework.jdbc.core.namedparam.NamedParameterJdbcTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class StrategyDiagnosisService {
  static final String RULE_VERSION="GEO_STRATEGY_V1";
  static final String NOTICE="诊断只反映指定时间内已验证、非演示人工观察的聚合表现和时间关联；不代表模型内部思维链，也不证明内容或整改动作与AI表现变化存在确定因果关系。";
  static final Set<String> PLATFORMS=Set.of("XHS_DIANDIAN","MEITUAN_WENXIAOTUAN","DOUBAO","DEEPSEEK");
  private final NamedParameterJdbcTemplate jdbc; private final ObjectMapper mapper; private final AuditService audit;
  public StrategyDiagnosisService(NamedParameterJdbcTemplate jdbc,ObjectMapper mapper,AuditService audit){this.jdbc=jdbc;this.mapper=mapper;this.audit=audit;}

  public Map<String,Object> config(Identity i,UUID merchant){assertMerchant(i,merchant);var rows=jdbc.queryForList("select * from geo_strategy_configs where tenant_id=:tenantId and merchant_id=:merchantId",base(i,merchant));return rows.isEmpty()?defaults(i,merchant):configView(rows.getFirst(),true);}
  @Transactional public Map<String,Object> saveConfig(Identity i,UUID merchant,StrategyDiagnosisController.ConfigInput in){assertMerchant(i,merchant);List<String> brands=clean(in.brandTerms()), platforms=clean(in.targetPlatforms());if(brands.isEmpty())throw bad("BRAND_TERMS_REQUIRED","至少需要一个品牌识别词");if(platforms.isEmpty())throw bad("TARGET_PLATFORMS_REQUIRED","至少需要一个目标AI平台");platforms=platforms.stream().map(String::toUpperCase).toList();if(platforms.stream().anyMatch(p->!PLATFORMS.contains(p)))throw bad("INVALID_AI_PLATFORM","存在不支持的AI平台");List<UUID> competitors=ids(in.competitorIds()),questions=ids(in.questionIds());assertOwned(i,merchant,"competitors",competitors);assertOwned(i,merchant,"consumer_questions",questions);OffsetDateTime now=OffsetDateTime.now();MapSqlParameterSource p=base(i,merchant).addValue("id",UUID.randomUUID()).addValue("brandTerms",json(brands)).addValue("ambiguousTerms",json(clean(in.ambiguousTerms()))).addValue("competitorIds",json(competitors)).addValue("questionIds",json(questions)).addValue("platforms",json(platforms)).addValue("domains",json(clean(in.ownedDomains()).stream().map(this::domain).filter(s->!s.isBlank()).toList())).addValue("notes",in.notes()).addValue("now",now).addValue("userId",i.userId());jdbc.update("insert into geo_strategy_configs(id,tenant_id,merchant_id,brand_terms,ambiguous_terms,competitor_ids,question_ids,target_platforms,owned_domains,notes,created_at,updated_at,created_by,updated_by,version) values(:id,:tenantId,:merchantId,cast(:brandTerms as jsonb),cast(:ambiguousTerms as jsonb),cast(:competitorIds as jsonb),cast(:questionIds as jsonb),cast(:platforms as jsonb),cast(:domains as jsonb),:notes,:now,:now,:userId,:userId,0) on conflict(tenant_id,merchant_id) do update set brand_terms=excluded.brand_terms,ambiguous_terms=excluded.ambiguous_terms,competitor_ids=excluded.competitor_ids,question_ids=excluded.question_ids,target_platforms=excluded.target_platforms,owned_domains=excluded.owned_domains,notes=excluded.notes,updated_at=excluded.updated_at,updated_by=excluded.updated_by,version=geo_strategy_configs.version+1",p);Map<String,Object> saved=config(i,merchant);audit.log(i.tenantId(),i.userId(),"GEO_STRATEGY_CONFIG_SAVED","GeoStrategyConfig",UUID.fromString(String.valueOf(saved.get("id"))),"保存M5监测配置");return saved;}
  public Map<String,Object> dashboard(Identity i,UUID merchant,Map<String,String> filters){Map<String,Object> config=config(i,merchant);Analysis a=analyze(i,merchant,config,time(filters.get("dateFrom")),time(filters.get("dateTo")));Map<String,Object> out=a.view();out.put("config",config);out.put("latestSnapshot",latest(i,merchant));out.put("causalityNotice",NOTICE);return out;}
  @Transactional public Map<String,Object> diagnose(Identity i,UUID merchant,OffsetDateTime from,OffsetDateTime to){Map<String,Object> config=config(i,merchant);Analysis a=analyze(i,merchant,config,from,to);OffsetDateTime now=OffsetDateTime.now();UUID run=UUID.randomUUID(),id=UUID.randomUUID();MapSqlParameterSource p=base(i,merchant).addValue("run",run).addValue("now",now).addValue("userId",i.userId());jdbc.update("insert into diagnostic_runs(id,tenant_id,merchant_id,status,provider,sample_note,created_at,updated_at,created_by,updated_by,version) values(:run,:tenantId,:merchantId,'COMPLETED','M5_MANUAL_OBSERVATION','M5诊断运行：只使用VERIFIED非演示AI观察',:now,:now,:userId,:userId,0)",p);p.addValue("id",id).addValue("rule",RULE_VERSION).addValue("from",a.from).addValue("to",a.to).addValue("count",a.rows.size()).addValue("config",json(config)).addValue("metrics",json(a.metrics)).addValue("platforms",json(a.platforms)).addValue("questions",json(a.questions)).addValue("competitors",json(a.competitors)).addValue("sources",json(a.sources)).addValue("gaps",json(a.gaps)).addValue("strategies",json(a.strategies)).addValue("notice",NOTICE);jdbc.update("insert into geo_diagnosis_snapshots(id,tenant_id,merchant_id,task_diagnostic_run_id,rule_version,sample_from,sample_to,observation_count,config_snapshot,metric_snapshot,platform_snapshot,question_snapshot,competitor_snapshot,source_snapshot,gap_snapshot,strategy_snapshot,causality_notice,created_at,created_by) values(:id,:tenantId,:merchantId,:run,:rule,:from,:to,:count,cast(:config as jsonb),cast(:metrics as jsonb),cast(:platforms as jsonb),cast(:questions as jsonb),cast(:competitors as jsonb),cast(:sources as jsonb),cast(:gaps as jsonb),cast(:strategies as jsonb),:notice,:now,:userId)",p);audit.log(i.tenantId(),i.userId(),"GEO_DIAGNOSIS_SNAPSHOT_CREATED","GeoDiagnosisSnapshot",id,"M5不可变诊断快照，样本="+a.rows.size());return snapshot(i,merchant,id);}
  public List<Map<String,Object>> snapshots(Identity i,UUID merchant){assertMerchant(i,merchant);return jdbc.queryForList("select id,rule_version,sample_from,sample_to,observation_count,metric_snapshot,created_at from geo_diagnosis_snapshots where tenant_id=:tenantId and merchant_id=:merchantId order by created_at desc",base(i,merchant));}
  public Map<String,Object> snapshot(Identity i,UUID merchant,UUID id){Map<String,Object> r=one("select * from geo_diagnosis_snapshots where id=:id and tenant_id=:tenantId and merchant_id=:merchantId",base(i,merchant).addValue("id",id));Map<String,Object> out=new LinkedHashMap<>();for(String key:List.of("id","rule_version","sample_from","sample_to","observation_count","causality_notice","created_at"))out.put(camel(key),r.get(key));out.put("config",map(r.get("config_snapshot")));out.put("metrics",map(r.get("metric_snapshot")));out.put("platformBreakdown",maps(r.get("platform_snapshot")));out.put("questionPerformance",maps(r.get("question_snapshot")));out.put("competitors",maps(r.get("competitor_snapshot")));out.put("sources",maps(r.get("source_snapshot")));out.put("gaps",map(r.get("gap_snapshot")));out.put("strategies",maps(r.get("strategy_snapshot")));return out;}
  @Transactional public List<Map<String,Object>> createTasks(Identity i,UUID merchant,UUID snapshotId){Map<String,Object> snap=snapshot(i,merchant,snapshotId);UUID run=UUID.fromString(String.valueOf(one("select task_diagnostic_run_id from geo_diagnosis_snapshots where id=:id and tenant_id=:tenantId and merchant_id=:merchantId",base(i,merchant).addValue("id",snapshotId)).get("task_diagnostic_run_id")));List<Map<String,Object>> out=new ArrayList<>();for(Map<String,Object>s:maps(snap.get("strategies"))){String code=String.valueOf(s.get("code"));var links=jdbc.queryForList("select t.* from geo_strategy_task_links l join optimization_tasks t on t.id=l.task_id and t.tenant_id=l.tenant_id where l.tenant_id=:tenantId and l.merchant_id=:merchantId and l.snapshot_id=:snapshotId and l.strategy_code=:code",base(i,merchant).addValue("snapshotId",snapshotId).addValue("code",code));if(!links.isEmpty()){out.add(links.getFirst());continue;}UUID tid=UUID.randomUUID(),lid=UUID.randomUUID();OffsetDateTime now=OffsetDateTime.now();MapSqlParameterSource p=base(i,merchant).addValue("taskId",tid).addValue("run",run).addValue("type",s.get("taskType")).addValue("title",s.get("title")).addValue("description",s.get("reason")+"。M5策略快照="+snapshotId+"，策略代码="+code).addValue("priority",s.get("priority")).addValue("questions",json(s.getOrDefault("questionIds",List.of()))).addValue("channels",json(s.getOrDefault("channels",List.of()))).addValue("now",now).addValue("userId",i.userId());jdbc.update("insert into optimization_tasks(id,tenant_id,merchant_id,diagnostic_run_id,task_type,title,description,priority,target_question_ids,recommended_channels,status,created_at,updated_at,created_by,updated_by,version) values(:taskId,:tenantId,:merchantId,:run,:type,:title,:description,:priority,cast(:questions as jsonb),cast(:channels as jsonb),'TODO',:now,:now,:userId,:userId,0)",p);p.addValue("id",lid).addValue("snapshotId",snapshotId).addValue("code",code);jdbc.update("insert into geo_strategy_task_links(id,tenant_id,merchant_id,snapshot_id,strategy_code,task_id,created_at,created_by) values(:id,:tenantId,:merchantId,:snapshotId,:code,:taskId,:now,:userId)",p);out.add(one("select * from optimization_tasks where id=:taskId and tenant_id=:tenantId",p));}return out;}

  private Analysis analyze(Identity i,UUID merchant,Map<String,Object> config,OffsetDateTime from,OffsetDateTime to){MapSqlParameterSource p=base(i,merchant);String sql="select o.*,q.question_text,q.commercial_value,q.decision_stage from ai_observations o join consumer_questions q on q.id=o.question_id and q.tenant_id=o.tenant_id where o.tenant_id=:tenantId and o.merchant_id=:merchantId and not o.deleted and o.demo=false and o.verification_status='VERIFIED'";List<String> platforms=strings(config.get("targetPlatforms"));if(!platforms.isEmpty()){sql+=" and o.ai_platform in (:platforms)";p.addValue("platforms",platforms);}List<UUID> qids=idsObject(config.get("questionIds"));if(!qids.isEmpty()){sql+=" and o.question_id in (:questionIds)";p.addValue("questionIds",qids);}if(from!=null){sql+=" and o.observed_at>=:from";p.addValue("from",from);}if(to!=null){sql+=" and o.observed_at<=:to";p.addValue("to",to);}List<Map<String,Object>> rows=jdbc.queryForList(sql,p);Map<String,Object> metrics=metrics(rows);List<Map<String,Object>> plats=group(rows,"ai_platform","platform"),qs=group(rows,"question_id","questionId");List<Map<String,Object>> comps=competitors(rows),sources=sources(rows,strings(config.get("ownedDomains")));Map<String,Object> gaps=gaps(i,merchant);List<Map<String,Object>> strategies=strategies(rows,metrics,plats,gaps);OffsetDateTime actualFrom=rows.stream().map(x->offset(x.get("observed_at"))).filter(Objects::nonNull).min(Comparator.naturalOrder()).orElse(from),actualTo=rows.stream().map(x->offset(x.get("observed_at"))).filter(Objects::nonNull).max(Comparator.naturalOrder()).orElse(to);return new Analysis(rows,actualFrom,actualTo,metrics,plats,qs,comps,sources,gaps,strategies);}
  Map<String,Object> metrics(List<Map<String,Object>> r){long total=r.size(),mention=count(r,"merchant_mentioned"),rec=count(r,"merchant_recommended"),top3=r.stream().filter(x->rank(x)!=null&&rank(x)<=3).count(),correct=r.stream().filter(x->"CORRECT".equals(x.get("fact_check_status"))).count(),errors=r.stream().filter(x->"ERROR".equals(x.get("fact_check_status"))).count();Map<String,Object>x=new LinkedHashMap<>();x.put("totalObservations",total);x.put("mentionedCount",mention);x.put("recommendedCount",rec);x.put("top3Count",top3);x.put("factCheckedCount",correct+errors);x.put("factErrorCount",errors);x.put("mentionRate",rate(mention,total));x.put("recommendationRate",rate(rec,total));x.put("top3Rate",rate(top3,total));x.put("factAccuracyRate",rate(correct,correct+errors));return x;}
  private List<Map<String,Object>> group(List<Map<String,Object>> rows,String field,String label){Map<String,List<Map<String,Object>>> g=new TreeMap<>();for(var r:rows)g.computeIfAbsent(String.valueOf(r.get(field)),k->new ArrayList<>()).add(r);List<Map<String,Object>> out=new ArrayList<>();for(var e:g.entrySet()){Map<String,Object>x=metrics(e.getValue());x.put(label,e.getKey());if("questionId".equals(label))x.put("questionText",e.getValue().getFirst().get("question_text"));out.add(x);}return out;}
  private List<Map<String,Object>> competitors(List<Map<String,Object>> rows){Map<String,Long> c=new HashMap<>();for(var r:rows)for(var x:maps(r.get("mentioned_competitors")))if(x.get("name")!=null)c.merge(String.valueOf(x.get("name")),1L,Long::sum);return c.entrySet().stream().sorted(Map.Entry.<String,Long>comparingByValue().reversed()).map(e->row("name",e.getKey(),"mentionedCount",e.getValue())).toList();}
  private List<Map<String,Object>> sources(List<Map<String,Object>> rows,List<String> owned){Map<String,Long> c=new TreeMap<>();for(var r:rows)for(var x:maps(r.get("cited_sources"))){String category=sourceCategory(String.valueOf(x.getOrDefault("url","")),String.valueOf(x.getOrDefault("sourceType","")),owned);c.merge(category,1L,Long::sum);}return c.entrySet().stream().map(e->row("category",e.getKey(),"count",e.getValue())).toList();}
  private Map<String,Object> gaps(Identity i,UUID merchant){Map<String,Object>x=new LinkedHashMap<>();x.put("platformAssetGaps",jdbc.queryForList("select gap_type,count(*) gap_count from platform_asset_gaps where tenant_id=:tenantId and merchant_id=:merchantId and status='OPEN' group by gap_type",base(i,merchant)));x.put("factIssues",jdbc.queryForList("select issue_type,severity,count(*) issue_count from ai_observation_fact_issues where tenant_id=:tenantId and merchant_id=:merchantId and not resolved group by issue_type,severity",base(i,merchant)));x.put("unverifiedFacts",jdbc.queryForObject("select count(*) from merchant_facts f join merchant_fact_versions v on v.id=f.current_version_id and v.tenant_id=f.tenant_id where f.tenant_id=:tenantId and f.merchant_id=:merchantId and not f.deleted and v.status<>'VERIFIED'",base(i,merchant),Long.class));return x;}
  private List<Map<String,Object>> strategies(List<Map<String,Object>> rows,Map<String,Object> metrics,List<Map<String,Object>> plats,Map<String,Object> gaps){List<Map<String,Object>> x=new ArrayList<>();Double mention=(Double)metrics.get("mentionRate"),rec=(Double)metrics.get("recommendationRate");if(rows.isEmpty())x.add(strategy("INSUFFICIENT_VERIFIED_OBSERVATIONS","补齐已核验人工观察样本","当前没有符合口径的非演示 VERIFIED 观察，不能输出具有误导性的表现结论。","AI_VISIBILITY","HIGH",List.of(),List.of()));else{if(mention==null||mention<0.5)x.add(strategy("IMPROVE_MENTION","提升品牌提及覆盖","在有效观察中品牌提及率偏低，优先补齐实体资料、服务信息和可核验第三方来源。","AI_VISIBILITY","HIGH",List.of(),List.of()));if(rec==null||rec<0.3)x.add(strategy("IMPROVE_RECOMMENDATION","提升推荐表现","商家被提及但推荐率不足，围绕高价值问题补齐服务差异、事实型FAQ和平台资料。","AI_VISIBILITY","HIGH",List.of(),List.of()));if(!((List<?>)gaps.get("factIssues")).isEmpty())x.add(strategy("CORRECT_FACT_ERRORS","纠正AI回答中的事实错误","存在未解决的地址、电话、服务或门店事实错误，应先更新事实证据和平台资料。","AI_FACT_CORRECTION","HIGH",List.of(),List.of()));if(!((List<?>)gaps.get("platformAssetGaps")).isEmpty())x.add(strategy("FIX_PLATFORM_ASSETS","修正平台资料差异","平台资产仍有开放 Gap，应优先完成名称、地址、电话、营业时间和服务项目核验。","ENTITY_PROFILE","MEDIUM",List.of(),List.of()));}return x;}
  private Map<String,Object> strategy(String code,String title,String reason,String type,String priority,List<?> q,List<?> c){return row("code",code,"title",title,"reason",reason,"taskType",type,"priority",priority,"questionIds",q,"channels",c);}
  private Map<String,Object> defaults(Identity i,UUID m){List<String> brand=jdbc.queryForList("select v.normalized_text from merchant_facts f join merchant_fact_versions v on v.id=f.current_version_id and v.tenant_id=f.tenant_id where f.tenant_id=:tenantId and f.merchant_id=:merchantId and f.fact_type='BRAND_NAME' and v.status='VERIFIED' and not f.deleted",base(i,m)).stream().map(x->String.valueOf(x.get("normalized_text"))).toList();if(brand.isEmpty())brand=List.of("未配置品牌词");List<UUID> qs=jdbc.queryForList("select id from consumer_questions where tenant_id=:tenantId and merchant_id=:merchantId and enabled and not deleted",base(i,m)).stream().map(x->(UUID)x.get("id")).toList();Map<String,Object>x=row("id",null,"brandTerms",brand,"ambiguousTerms",List.of(),"competitorIds",List.of(),"questionIds",qs,"targetPlatforms",List.copyOf(PLATFORMS),"ownedDomains",List.of(),"notes","默认监测配置，保存后生效","persisted",false);return x;}
  private Map<String,Object> configView(Map<String,Object> r,boolean persisted){return row("id",r.get("id"),"brandTerms",strings(r.get("brand_terms")),"ambiguousTerms",strings(r.get("ambiguous_terms")),"competitorIds",idsObject(r.get("competitor_ids")),"questionIds",idsObject(r.get("question_ids")),"targetPlatforms",strings(r.get("target_platforms")),"ownedDomains",strings(r.get("owned_domains")),"notes",r.get("notes"),"version",r.get("version"),"persisted",persisted);}
  private Map<String,Object> latest(Identity i,UUID m){var x=jdbc.queryForList("select id,rule_version,observation_count,created_at from geo_diagnosis_snapshots where tenant_id=:tenantId and merchant_id=:merchantId order by created_at desc limit 1",base(i,m));return x.isEmpty()?null:x.getFirst();}
  private void assertOwned(Identity i,UUID m,String table,List<UUID> ids){if(ids.isEmpty())return;Long n=jdbc.queryForObject("select count(*) from "+table+" where tenant_id=:tenantId and merchant_id=:merchantId and id in (:ids) and "+("consumer_questions".equals(table)?"not deleted":"not deleted"),base(i,m).addValue("ids",ids),Long.class);if(n!=ids.size())throw bad("INVALID_SCOPE_REFERENCE","存在不属于当前商家的配置项");}
  private void assertMerchant(Identity i,UUID m){if(jdbc.queryForList("select id from merchants where id=:merchantId and tenant_id=:tenantId and not deleted",base(i,m)).isEmpty())throw new ApiException(HttpStatus.NOT_FOUND,"NOT_FOUND","商家不存在或无权访问");}
  private MapSqlParameterSource base(Identity i,UUID m){return new MapSqlParameterSource().addValue("tenantId",i.tenantId()).addValue("merchantId",m);}private Map<String,Object> one(String sql,MapSqlParameterSource p){var x=jdbc.queryForList(sql,p);if(x.isEmpty())throw new ApiException(HttpStatus.NOT_FOUND,"NOT_FOUND","数据不存在或无权访问");return x.getFirst();}private ApiException bad(String c,String msg){return new ApiException(HttpStatus.BAD_REQUEST,c,msg);}private String json(Object v){try{return mapper.writeValueAsString(v);}catch(Exception e){throw new IllegalStateException(e);}}@SuppressWarnings("unchecked")private List<Map<String,Object>> maps(Object raw){try{return raw==null?List.of():mapper.readValue(String.valueOf(raw),new TypeReference<List<Map<String,Object>>>(){});}catch(Exception e){return List.of();}}@SuppressWarnings("unchecked")private Map<String,Object> map(Object raw){try{return raw==null?Map.of():mapper.readValue(String.valueOf(raw),new TypeReference<Map<String,Object>>(){});}catch(Exception e){return Map.of();}}private List<String> strings(Object raw){if(raw instanceof Collection<?> c)return c.stream().map(String::valueOf).toList();try{return mapper.readValue(String.valueOf(raw),new TypeReference<List<String>>(){});}catch(Exception e){return List.of();}}private List<UUID> idsObject(Object raw){return strings(raw).stream().flatMap(x->{try{return java.util.stream.Stream.of(UUID.fromString(x));}catch(Exception e){return java.util.stream.Stream.empty();}}).toList();}private List<UUID> ids(List<UUID>x){return x==null?List.of():x.stream().filter(Objects::nonNull).distinct().toList();}private List<String> clean(List<String>x){return x==null?List.of():x.stream().filter(Objects::nonNull).map(String::trim).filter(s->!s.isBlank()).distinct().toList();}private OffsetDateTime time(String x){try{return x==null||x.isBlank()?null:OffsetDateTime.parse(x);}catch(Exception e){throw bad("INVALID_DATE","日期必须为ISO-8601");}}private OffsetDateTime offset(Object value){if(value instanceof OffsetDateTime time)return time;if(value instanceof java.sql.Timestamp stamp)return stamp.toInstant().atOffset(java.time.ZoneOffset.UTC);if(value instanceof java.time.LocalDateTime time)return time.atOffset(java.time.ZoneOffset.UTC);return null;}private long count(List<Map<String,Object>>r,String key){return r.stream().filter(x->Boolean.TRUE.equals(x.get(key))).count();}private Integer rank(Map<String,Object>x){return x.get("recommendation_rank") instanceof Number n?n.intValue():null;}private Double rate(long n,long d){return d==0?null:(double)n/d;}private String domain(String s){try{URI u=new URI(s.contains("://")?s:"https://"+s);return u.getHost()==null?"":u.getHost().toLowerCase().replaceFirst("^www\\.","");}catch(Exception e){return "";}}String sourceCategory(String url,String type,List<String> owned){String d=domain(url);if(!d.isBlank()&&owned.stream().anyMatch(x->d.equals(x)||d.endsWith("."+x)))return "OWNED";String t=type.toUpperCase();if(t.contains("DIANPING")||t.contains("MEITUAN"))return "LOCAL_PLATFORM";if(t.contains("XHS")||t.contains("XIAOHONGSHU"))return "SOCIAL_PLATFORM";if(!d.isBlank())return "EXTERNAL_WEB";return "UNKNOWN";}private Map<String,Object> row(Object...v){Map<String,Object>x=new LinkedHashMap<>();for(int n=0;n<v.length;n+=2)x.put(String.valueOf(v[n]),v[n+1]);return x;}private String camel(String x){String[] p=x.split("_");StringBuilder b=new StringBuilder(p[0]);for(int n=1;n<p.length;n++)b.append(Character.toUpperCase(p[n].charAt(0))).append(p[n].substring(1));return b.toString();}
  private record Analysis(List<Map<String,Object>> rows,OffsetDateTime from,OffsetDateTime to,Map<String,Object> metrics,List<Map<String,Object>> platforms,List<Map<String,Object>> questions,List<Map<String,Object>> competitors,List<Map<String,Object>> sources,Map<String,Object> gaps,List<Map<String,Object>> strategies){Map<String,Object> view(){Map<String,Object> result=new LinkedHashMap<>();result.put("metrics",metrics);result.put("platformBreakdown",platforms);result.put("questionPerformance",questions);result.put("competitors",competitors);result.put("sources",sources);result.put("gaps",gaps);result.put("strategies",strategies);result.put("sampleCount",rows.size());return result;}}
}
